    {id=141,name="New Tanaan Crafting Mastery",icon=163,cls=65535,cost=3,era=2,mr=3,desc="Training with the sages and merchants of New Tanaan gives adventurers the chance to hone their crafting skills.  For each rank of this ability that you purchase, you are able to raise an additional trade skill past its Specialization level "},
