    {id=150,name="Mastery of the Past",icon=163,cls=15376,cost=3,era=3,mr=3,desc="This ability makes it impossible for you to fizzle spells up to a certain level.  Rank 1 - level 54.  Rank 2 - level 56.  Rank 3 - level 58.  Rank 4 - level 62.  Rank 5 - level 64.  Rank 6 - level 66.  Rank 7 - level 67.  Rank 8 - level 69.",pr={{a=26,r=3}}},
