    {id=160,name="Hastened Root",icon=6,cls=2048,cost=2,era=3,mr=3,desc="The first three ranks of this ability decrease the amount of time required between uses of Strong Root by ten percent per rank.  Additional ranks further decrease the time required between uses of Strong Root and also increase the strength ",pr={{a=117,r=1}}},
    {id=161,name="Hastened Mending",icon=99,cls=21504,cost=2,era=3,mr=3,desc="This ability decreases the amount of time required between uses of Mend Companion by ten percent per rank. You may train in this ability once each level, upon reaching level 63.",pr={{a=58,r=1}}},
