    {id=185,name="Spirit of the Wood",icon=49,cls=32,cost=4,era=4,mr=2,desc="For a brief time, you are able to commune with the woodland spirits who provide your party with exceptional regenerative abilities and a protective shield of armor and thorns.  Additional ranks increase the power of this effect"},
    {id=186,name="Bestial Frenzy",icon=6,cls=16384,cost=2,era=4,mr=5,desc="Each rank in this ability improves your chance of performing a double attack in any given combat round."},
