    {id=199,name="Boastful Bellow",icon=161,cls=0,cost=6,era=4,mr=1,desc="This ability allows you to bellow with a force that causes physical harm to your enemies as well as potentially interfering with their spell casting.  Additional ranks increase the highest level of NPC that you can stun with your Boastful B",pr={{a=30,r=1}}},
