    {id=201,name="Touch of the Wicked",icon=6,cls=16,cost=2,era=4,mr=3,desc="This ability decreases the amount of time required between uses of Harm Touch and its upgrades. Each rank reduces the reuse time by 12 minutes. You gain the ability to train an additional rank at levels 61, 63, 65 and 76.",pr={{a=6000,r=11}}},
    {id=202,name="Punishing Blade",icon=6,cls=32841,cost=2,era=4,mr=5,desc="This ability increases the chance of scoring an extra hit with all two-handed weapons. Each rank in this ability increases the chance of scoring an extra hit with all two-handed weapons that you wield."},
    {id=203,name="Speed of the Knight",icon=6,cls=20,cost=3,era=4,mr=3,desc="Each rank in this ability increases the chance of scoring an extra hit with all two-handed weapons that you wield."},
    {id=204,name="Shroud of Stealth",icon=6,cls=256,cost=6,era=4,mr=1,desc="This ability provides a previously unheard of level of stealth.  The Rogue is able to draw shadows about himself so completely, even creatures that are normally not fooled by such trickery are frequently unable to see him. You may train in "},
