    {id=208,name="Call of Xuzl",icon=105,cls=2048,cost=3,era=4,mr=3,desc="This ability calls a number of swords of Xuzl into existence directed at a target.  The swords attack the target until they dissipate 45 seconds later.  The initial rank of this ability calls two swords.  Additional ranks increase the overa"},
    {id=209,name="Hastened Stealth",icon=6,cls=256,cost=3,era=4,mr=3,desc="This ability reduces the time between which you may attempt to hide or evade by one second per rank.  You may train the ranks of this ability at or after levels 61, 62, and 63."},
